#!/usr/bin/env python3
"""Compute and print the first 20 Fibonacci numbers."""

def fibonacci(n):
    """Generate the first n Fibonacci numbers."""
    if n <= 0:
        return []
    elif n == 1:
        return [0]

    fib_sequence = [0, 1]
    for i in range(2, n):
        fib_sequence.append(fib_sequence[i-1] + fib_sequence[i-2])

    return fib_sequence

# Generate first 20 Fibonacci numbers
fib_numbers = fibonacci(20)

# Print as comma-separated list
print(", ".join(map(str, fib_numbers)))
